#!/usr/bin/env python
"""
Bootstrap: Glycan De Novo Binder Design Module
  - Sugar target descriptors (8 monosaccharides)
  - Receptor pharmacophore scoring (CH-pi, HB, desolvation, boronic)
  - Selectivity scoring vs competitor panel
  - NSGA-II Pareto generation (affinity x selectivity x synthesizability)
  - 50 tests

Requires: glycan module + core/de_novo_generator.py + core/pareto.py + RDKit

Usage: python bootstrap_glycan_denovo.py
  (run from MABE repo root)
"""

import base64, os, sys

if os.path.isfile("core/universal_schema.py"):
    root = "."
elif os.path.isfile(os.path.join("..", "core", "universal_schema.py")):
    root = ".."
    os.chdir(root)
else:
    print("ERROR: Run from MABE repo root")
    sys.exit(1)

if not os.path.isdir("glycan"):
    print("ERROR: glycan/ directory not found")
    sys.exit(1)

FILES = {
    'glycan/de_novo_binder.py': '',
    'glycan/tests/test_de_novo_binder.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")

print("")
print("Done. Run:")
print("  python -m pytest glycan/tests/test_de_novo_binder.py -v")